/**
 * @fileoverview Tabs events — centralised event binding via AbortController.
 * @module module/Tabs/events
 */

import razyui from '../../index.js';
import { TabsDef as DEF } from '../Tabs.def.js';

/**
 * Create the handler context object consumed by DEF event dispatchers.
 * Uses a lazy provider function so properties always reflect current state.
 *
 * @param {Function} provider — () => { tabs, activeIndex, ... }
 * @returns {object} handler context with live getters
 */
export function createHandlerCtx(provider) {
    return {
        get tabs()        { return provider().tabs; },
        get activeIndex() { return provider().activeIndex; },
        get orientation() { return provider().orientation; },
        get activation()  { return provider().activation; },
        select(i)         { provider().select(i); },
        close(i)          { provider().close(i); },
        findNextTab(f, d) { return provider().findNextTab(f, d); },
    };
}

/**
 * Bind delegated click and keydown events on the tab list.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {HTMLElement} list — event delegation root (tab list)
 * @param {object} ctx — handler context from createHandlerCtx
 * @returns {AbortController}
 */
export function bindEvents(list, ctx) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    const $list = razyui(list);

    $list.on('click',   e => DEF.handlers.tab.click(ctx, e),   opts);
    $list.on('keydown', e => DEF.handlers.tab.keydown(ctx, e), opts);

    return ac;
}
