/**
 * @fileoverview Tabs state — pure state machine transitions + reactive state wiring.
 * @module module/Tabs/state
 */

/**
 * Pure state machine transition map for per-tab states.
 * Side-effect free — paired with view effects in view.js.
 */
export const TAB_TRANSITIONS = {
    initial: 'inactive',
    states: {
        inactive: { on: { SELECT: 'active' } },
        active:   { on: { DESELECT: 'inactive' } },
        disabled: { on: { ENABLE: 'inactive' } },
    },
};

/**
 * Create reactive tabs state and synchronise with per-tab state machines.
 *
 * When `activeIndex` changes, the matching tab SM receives 'SELECT'
 * and the previously active SM receives 'DESELECT'. Disabled tabs are skipped.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @param {import('../shared/StateMachine.js').StateMachine[]} tabSMs — per-tab SM instances
 * @returns {{ ref: object, setState: Function }}
 */
export function createReactiveState(stateFn, tabSMs) {
    const stateSet = stateFn({ activeIndex: -1 });
    const ref      = stateSet[0];
    const setState = stateSet[1];

    stateSet.effect(() => {
        const idx = ref.activeIndex;
        tabSMs.forEach((sm, i) => {
            if (sm.current === 'disabled') return;
            if (i === idx && sm.current !== 'active')  sm.send('SELECT');
            else if (i !== idx && sm.current === 'active') sm.send('DESELECT');
        });
    });

    return { ref, setState };
}
