/**
 * @fileoverview Tabs helpers — pure utility functions.
 * @module module/Tabs/helpers
 */

/**
 * Find the next non-disabled tab starting from `from`, moving in `dir`.
 * Wraps around if needed.
 *
 * @param {HTMLElement[]} tabs — ordered tab button array
 * @param {number} from — starting index (exclusive)
 * @param {number} dir  — direction: 1 (forward) or -1 (backward)
 * @param {boolean} [wrap=true] — whether to wrap around
 * @returns {number} found index, or -1 if none available
 */
export function findNextTab(tabs, from, dir, wrap = true) {
    const len = tabs.length;
    if (!len) return -1;

    let idx = from + dir;

    // Non-wrapping check first
    for (let i = 0; i < len; i++) {
        if (idx < 0) idx = wrap ? len - 1 : -1;
        if (idx >= len) idx = wrap ? 0 : -1;
        if (idx < 0) return -1;
        if (!tabs[idx].disabled) return idx;
        idx += dir;
    }

    return -1;
}
