import { TRUNCATE, TRANSITION_COLORS, SCROLLBAR_THIN } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:       'tabs',
    LIST:       'tabs-list',
    TAB:        'tabs-tab',
    PANEL:      'tabs-panel',
    ICON:       'tabs-icon',
    CLOSE:      'tabs-close',
    ACTIVE:     'is-active',
    DISABLED:   'is-disabled',
    VERTICAL:   'is-vertical',
    CLOSABLE:   'is-closable',
});

/** ARIA role values */
export const ARIA = Object.freeze({
    TABLIST:  'tablist',
    TAB:      'tab',
    TABPANEL: 'tabpanel',
});

/** DOM selectors */
export const SEL = Object.freeze({
    TAB:   '[data-tab]',
    CLOSE: '.tabs-close',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    activeIndex: 0,
    orientation: 'horizontal',
    activation: 'automatic',
    closable: false,
    variant: null,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('Tabs', {
    ROOT        : { class: 'tabs-container', aliases: ['tabs', 'root', 'container'] },
    LIST        : { class: 'tabs-list', aliases: ['list', 'tablist'] },
    TAB         : { class: 'tabs-tab', aliases: ['tab'] },
    PANEL       : { class: 'tabs-panel', aliases: ['panel', 'content'] },
    ICON        : { class: 'tabs-icon', aliases: ['icon'] },
    CLOSE       : { class: 'tabs-close', aliases: ['close'] },
    VERT_ROOT   : { class: 'tabs-container-vertical' },
    VERT_LIST   : { class: 'tabs-list-vertical' },
    BOXED_ROOT  : { class: 'tabs-container-boxed' },
    BOXED_TAB   : { class: 'tabs-tab-boxed' },
    PILLS_ROOT  : { class: 'tabs-container-pills' },
    PILLS_TAB   : { class: 'tabs-tab-pills' },
});

